What is the output of the following program?
#include <stdio.h>
void main ()
{
const int a=4;
float b;
b=++a;
printf("%d, %f", a, ++b);
}

What is the output of the following program?
#include <stdio.h>
#define I char
void main ()
{
I i=65;
printf("sizeof(i) = %d", sizeof(i));
}

What is the output of the following program?
#include <stdio.h>
void main()
{
int x=0, y=0;
if(x && y++)
printf("%d..%d", x++, y);
printf("%d..%d", x, y);
}

What is the output of the following program?
#include <stdio.h>
enum colors {BLACK, BLUE, CYAN};
void main ()
{
printf ("%d..%d..%d", BLACK, BLUE, CYAN);
}

What is the output of the following program?
#include <stdio.h>
void main ()
{
char xy=0;
for(;xy>0;xy++);
printf("%d\n", xy);
}

